53	          <Typography.Text strong ellipsis style={{ display: 'block' }}>
54	            {name}
55	          </Typography.Text>
56	          <Typography.Text type="secondary" style={{ fontSize: 12 }} ellipsis>
57	            {asset.namespace}
58	          </Typography.Text>
59	        </div>
60	      ),
61	    },
62	    {
63	      title: 'Env',
64	      dataIndex: 'env',
65	      width: 90,
66	      render: (env: string | null) =>
67	        env ? <Tag>{env}</Tag> : <Typography.Text type="secondary">—</Typography.Text>,
68	    },
69	    {
70	      title: 'Suites',
71	      dataIndex: 'suite_count',
72	      width: 90,
73	      align: 'center',
74	    },
75	    {
76	      title: 'Health',
77	      key: 'health',
78	      width: 130,
79	      render: (_: unknown, asset) => <AssetHealthTag summary={asset} />,
80	    },
81	    {
82	      title: 'Last seen',
83	      dataIndex: 'last_seen',
84	      width: 200,
85	      render: (ts: string) => (
86	        <Typography.Text type="secondary" style={{ fontSize: 12 }}>
87	          {formatTimestamp(ts)}
