1	import type { AssetSummary, RunOutcome } from '../../api/assets';
2	
3	/**
4	 * Asset health derivation (#760) — pure, so it can be unit-tested without
5	 * rendering antd (kept out of the `.tsx` so the tag component can fast-refresh).
6	 *
7	 * Health considers BOTH axes the Results surface distinguishes (`resultsFormat`'s
8	 * `RUN_STATUS_COLORS` conventions): the run's *execution* status and the checks'
9	 * *data-quality* severity. Precedence:
10	 * - a failing check tier present            → that tier (warn < fail < critical)
11	 * - latest run failed operationally         → "Run failed" (error — never green:
12	 *   a failed run wrote no results, so severity alone would read passing)
13	 * - latest run still queued/running         → "Queued"/"Running" (not green yet)
14	 * - latest run cancelled, nothing evaluated → "Cancelled"
15	 * - a finished run, all evaluated passed    → "Passing"
16	 * - nothing has run yet                     → "No runs"
17	 */
18	export type Health = { label: string; color: string };
19	
20	const SEVERITY_HEALTH: Record<'warn' | 'fail' | 'critical', Health> = {
21	  warn: { label: 'Warning', color: 'warning' },
22	  fail: { label: 'Failing', color: 'error' },
23	  critical: { label: 'Critical', color: 'magenta' },
24	};
25	
26	// Execution-status healths, colour-matched to resultsFormat.RUN_STATUS_COLORS.
27	const RUN_FAILED_HEALTH: Health = { label: 'Run failed', color: 'error' };
28	const STATUS_HEALTH: Record<string, Health> = {
29	  queued: { label: 'Queued', color: 'default' },
30	  running: { label: 'Running', color: 'processing' },
31	  cancelled: { label: 'Cancelled', color: 'warning' },
32	};
33	
34	/** Asset-level health from the summary aggregation (severity + run-state flags). */
35	export function assetHealth(
36	  summary: Pick<
37	    AssetSummary,
38	    'worst_severity' | 'last_run_at' | 'has_failed_run' | 'has_active_run'
39	  >,
40	): Health {
41	  if (summary.worst_severity) return SEVERITY_HEALTH[summary.worst_severity];
42	  if (summary.has_failed_run) return RUN_FAILED_HEALTH;
43	  if (summary.has_active_run) return STATUS_HEALTH.running;
44	  if (summary.last_run_at !== null) return { label: 'Passing', color: 'success' };
45	  return { label: 'No runs', color: 'default' };
46	}
47	
48	/** Per-suite health from its latest run (execution status + severity). */
49	export function runHealth(run: RunOutcome): Health {
50	  if (run.run_id === null) return { label: 'No runs', color: 'default' };
51	  if (run.worst_severity) return SEVERITY_HEALTH[run.worst_severity];
52	  if (run.status === 'failed') return RUN_FAILED_HEALTH;
53	  const byStatus = run.status !== null ? STATUS_HEALTH[run.status] : undefined;
54	  if (byStatus) return byStatus;
55	  return { label: 'Passing', color: 'success' };
56	}
