const mockList = vi.mocked(listAssets);

const ASSET: AssetSummary = {
  id: 'a1',
  namespace: 'snowflake://acct',
  name: 'ANALYTICS.PUBLIC.ORDERS',
  env: 'dev',
  description: null,
  owner_user_id: null,
